SELECT COUNT(*) FROM user u
WHERE 1=1
AND u.dept_id = #{deptId}
AND u.username LIKE CONCAT('%',#{username},'%')
AND u.status = #{status}

mapper.update:
UPDATE user
username = #{username}, password = #{password}, phone = #{phone}, dept_id = #{deptId}, status = #{status}, update_time = NOW()
WHERE user_id = #{userId}
